                                    else
                                        ShowNotification("AP SPAM", "All commands on cooldown")
                                    end
                                else
                                    ShowNotification("AP SPAM", "No owner found")
                                end
                            end
                        end)
                    end
                else
                    if not canUseAdminAction(plr) then return end
                    ShowNotification("ADMIN", "Attempting " .. def.cmd .. " on " .. plr.Name)
