        local function updateBlBtn()
            local bl = isBlacklisted(plr.Name)
            blBtn.Text = bl and "🔓" or "🚫"
            blBtn.BackgroundColor3 = bl and Color3.fromRGB(180,40,40) or Color3.fromRGB(35,37,43)
            blBtn.TextColor3 = Theme.TextPrimary
